import type { AgentId } from './constants';

export interface Office3DApi {
  init: (el: HTMLElement, labelsEl: HTMLElement | null, notifyEl: HTMLElement | null) => boolean;
  destroy: () => void;
  gatherAtMeeting: () => void;
  scatterToDesks: () => void;
  onMessage: (agentId: string, text: string, meta?: Record<string, unknown>) => void;
  onStatus: (agentId: string, status: string) => void;
  goToDesk: (id: string) => void;
  visitColleague: (id: string) => void;
  pushTopNotification: (meta: Record<string, unknown>, text: string) => void;
  clearNotifications: () => void;
  resetCamera: () => void;
  focusAgent: (id: string) => void;
  onQuestion: (agentId: string, payload: Record<string, unknown>) => void;
  onQuestionAnswered: (agentId: string) => void;
  onAction: (agentId: string, payload: Record<string, unknown>) => void;
  onActionResolved: (agentId: string) => void;
  getGfxTier?: () => string;
}

export function isAgentId(id: string): id is AgentId {
  return ['orchestrator', 'designer', 'frontend', 'backend', 'owencloud'].includes(id);
}

if (typeof globalThis.process === 'undefined') {
  (globalThis as typeof globalThis & { process: { env: { NODE_ENV: string } } }).process = {
    env: { NODE_ENV: 'production' },
  };
}

import { createRoot, Root } from 'react-dom/client';
import { useEffect, useRef, useState } from 'react';
import { AGENTS } from './constants';
import { detectQualityTier } from './quality';
import { applyScenePalette, getInitialThemeId } from './theme/palette';
import { OfficeScene } from './OfficeScene';
import type { Office3DApi } from './bridge-api';
import { isAgentId } from './bridge-api';
import type { CameraRigHandle } from './components/CameraRig';
import { setLabelLayer } from './components/DomLabels';
import { bindNotifyStack, clearNotifications, pushTopNotification } from './notifications';
import { OfficeStore } from './state/officeStore';

let root: Root | null = null;
let store: OfficeStore | null = null;
let containerEl: HTMLElement | null = null;
export const globalCameraRef = { current: null as CameraRigHandle | null };

function SceneHost() {
  const camRef = useRef<CameraRigHandle | null>(null);
  const [themeId, setThemeId] = useState(getInitialThemeId);

  useEffect(() => {
    const onTheme = (ev: Event) => {
      const id = (ev as CustomEvent<{ themeId?: string }>).detail?.themeId || 'light';
      applyScenePalette(id);
      setThemeId(id);
    };
    window.addEventListener('office-theme-change', onTheme);
    return () => window.removeEventListener('office-theme-change', onTheme);
  }, []);

  if (!store) return null;

  return (
    <OfficeScene
      key={themeId}
      store={store}
      cameraRef={camRef}
      onCameraReady={(h) => {
        globalCameraRef.current = h;
      }}
    />
  );
}

function mountScene(el: HTMLElement) {
  store = new OfficeStore(AGENTS);
  root = createRoot(el);
  root.render(<SceneHost />);
}

function showInitError(el: HTMLElement, msg: string) {
  const box = document.createElement('div');
  box.className = 'office-3d-error';
  box.innerHTML = `<strong>3D офис не загрузился</strong><p>${msg}</p><p>Обновите страницу (Ctrl+F5). Чат справа работает.</p>`;
  el.appendChild(box);
}

const api: Office3DApi = {
  init(el, labelsEl, notifyEl) {
    try {
      containerEl = el;
      el.innerHTML = '';
      const host = document.createElement('div');
      host.className = 'office-canvas-host-inner';
      host.style.width = '100%';
      host.style.height = '100%';
      el.appendChild(host);
      setLabelLayer(labelsEl);
      bindNotifyStack(notifyEl);

      const onSceneError = (ev: Event) => {
        const msg = (ev as CustomEvent<{ message?: string }>).detail?.message || 'Ошибка рендера';
        showInitError(el, msg);
      };
      window.addEventListener('office3d-error', onSceneError);

      mountScene(host);
      return true;
    } catch (err) {
      console.error('Office3D R3F init failed:', err);
      showInitError(el, err instanceof Error ? err.message : String(err));
      return false;
    }
  },

  destroy() {
    root?.unmount();
    root = null;
    store = null;
    containerEl = null;
    globalCameraRef.current = null;
    setLabelLayer(null);
    window.__office3dReady = false;
  },

  gatherAtMeeting() {
    store?.gatherAtMeeting();
  },

  scatterToDesks() {
    store?.scatterToDesks();
  },

  onMessage(agentId, text, meta) {
    if (!isAgentId(agentId) || !store) return;
    const m = meta || store.getState().agents[agentId].meta;
    store.onMessage(agentId, text);
    pushTopNotification(
      {
        name: (m as { agent_name?: string }).agent_name || (m as { name?: string }).name,
        emoji: (m as { emoji?: string }).emoji,
        color: (m as { color?: string }).color,
      },
      text
    );
  },

  onStatus(agentId, status) {
    if (!isAgentId(agentId) || !store) return;
    store.onStatus(agentId, status);
  },

  goToDesk(id) {
    if (!isAgentId(id) || !store) return;
    store.goToDesk(id);
  },

  visitColleague(id) {
    if (!isAgentId(id) || !store) return;
    store.visitColleague(id);
  },

  pushTopNotification(meta, text) {
    pushTopNotification(meta, text);
  },

  clearNotifications() {
    clearNotifications();
  },

  resetCamera() {
    globalCameraRef.current?.reset();
  },

  focusAgent(id) {
    if (!isAgentId(id) || !store) return;
    globalCameraRef.current?.focusAgent(id);
    store.showBubble(id, `${store.getState().agents[id].meta.name} — кабинет`);
    setTimeout(() => store?.hideBubble(id), 5000);
  },

  onQuestion(agentId, payload) {
    if (!isAgentId(agentId) || !store) return;
    const text = String(payload.text || '');
    store.visitUser(agentId);
    store.showBubble(agentId, text);
    const meta = AGENTS[agentId];
    pushTopNotification({ name: meta.name, emoji: meta.emoji, color: meta.color }, text);
  },

  onQuestionAnswered(agentId) {
    if (!isAgentId(agentId) || !store) return;
    store.showBubble(agentId, 'Спасибо!');
    setTimeout(() => store?.leaveUser(agentId), 2200);
  },

  onAction(agentId, payload) {
    if (!isAgentId(agentId) || !store) return;
    const cmd = String(payload.command || '');
    const text = cmd ? `Команда: ${cmd.slice(0, 80)}` : 'Запрос на выполнение команды';
    store.visitUser(agentId);
    store.showBubble(agentId, text);
    const meta = AGENTS[agentId];
    pushTopNotification({ name: meta.name, emoji: meta.emoji, color: meta.color }, text);
  },

  onActionResolved(agentId) {
    if (!isAgentId(agentId) || !store) return;
    store.showBubble(agentId, 'Готово');
    setTimeout(() => store?.leaveUser(agentId), 2200);
  },

  getGfxTier() {
    return detectQualityTier();
  },
};

window.Office3DR3F = api;
window.Office3D = api;

export type { Office3DApi };
export default api;

import { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { DoubleSide, Group, Mesh, MeshStandardMaterial } from 'three';
import { BLOOM_LAYER } from '../constants';
import type { AgentRuntime } from '../state/officeStore';

interface AgentProps {
  agent: AgentRuntime;
}

export function Agent({ agent }: AgentProps) {
  const groupRef = useRef<Group>(null);
  const leftArmRef = useRef<Mesh>(null);
  const rightArmRef = useRef<Mesh>(null);
  const headRef = useRef<Mesh>(null);
  const bodyRef = useRef<Mesh>(null);
  const haloRef = useRef<Mesh>(null);

  const { meta, pos, rot, state, typing, typingPhase, idlePhase, talkingGlow } = agent;

  useFrame((_, dt) => {
    const g = groupRef.current;
    if (!g) return;

    g.position.set(pos.x, 0, pos.z);
    g.rotation.y = rot;

    let yBob = 0;
    if (state === 'walking' || state === 'visiting') {
      yBob = Math.abs(Math.sin(performance.now() * 0.012)) * 0.06;
    } else if (typing) {
      yBob = Math.sin(typingPhase * 0.5) * 0.02;
    } else {
      yBob = Math.sin(idlePhase * 2) * 0.008;
    }
    g.position.y = yBob;

    if (!typing && state === 'idle') {
      const breath = 1 + Math.sin(idlePhase * 2) * 0.009;
      g.scale.set(1, breath, 1);
      g.rotation.z = Math.sin(idlePhase * 0.8) * 0.018;
    } else {
      g.scale.set(1, 1, 1);
      g.rotation.z *= 0.9;
    }

    if (headRef.current && !typing && state === 'idle') {
      headRef.current.rotation.y = Math.sin(idlePhase * 0.35) * 0.09;
    } else if (headRef.current) {
      headRef.current.rotation.y *= 0.85;
    }

    if (leftArmRef.current && rightArmRef.current) {
      if (typing) {
        leftArmRef.current.rotation.x = -0.6 + Math.sin(typingPhase) * 0.25;
        rightArmRef.current.rotation.x = -0.5 + Math.cos(typingPhase * 1.2) * 0.3;
      } else {
        leftArmRef.current.rotation.x *= 0.9;
        rightArmRef.current.rotation.x *= 0.9;
      }
    }

    if (bodyRef.current && talkingGlow > 0.1) {
      bodyRef.current.position.z = Math.sin(performance.now() * 0.008) * 0.03 * talkingGlow;
    } else if (bodyRef.current) {
      bodyRef.current.position.z *= 0.9;
    }

    if (haloRef.current) {
      const glow = talkingGlow > 0.05 ? talkingGlow : state === 'talking' ? 0.5 : 0;
      if (glow > 0.02) {
        const mat = haloRef.current.material as MeshStandardMaterial;
        mat.emissiveIntensity = glow * (0.9 + Math.sin(performance.now() * 0.006) * 0.15);
        haloRef.current.visible = true;
        haloRef.current.scale.setScalar(1 + glow * 0.12);
      } else if (haloRef.current.visible) {
        haloRef.current.visible = false;
      }
    }
  });

  return (
    <group ref={groupRef}>
      <mesh ref={bodyRef} position={[0, 0.85, 0]} castShadow>
        <boxGeometry args={[0.42, 0.5, 0.28]} />
        <meshStandardMaterial color={meta.color} roughness={0.45} metalness={0.18} envMapIntensity={0.85} />
      </mesh>
      <mesh position={[0, 0.38, 0]} castShadow>
        <boxGeometry args={[0.38, 0.45, 0.26]} />
        <meshStandardMaterial color="#1a2336" roughness={0.65} metalness={0.08} />
      </mesh>
      <mesh ref={headRef} position={[0, 1.28, 0]} castShadow>
        <sphereGeometry args={[0.2, 16, 16]} />
        <meshStandardMaterial color="#f1c9a2" roughness={0.78} />
      </mesh>
      <mesh ref={leftArmRef} position={[-0.3, 0.88, 0]} castShadow>
        <boxGeometry args={[0.1, 0.38, 0.1]} />
        <meshStandardMaterial color={meta.color} roughness={0.5} metalness={0.1} />
      </mesh>
      <mesh ref={rightArmRef} position={[0.3, 0.88, 0]} castShadow>
        <boxGeometry args={[0.1, 0.38, 0.1]} />
        <meshStandardMaterial color={meta.color} roughness={0.5} metalness={0.1} />
      </mesh>

      {/* Emissive halo for selective bloom when agent talks */}
      <mesh ref={haloRef} position={[0, 1.55, 0]} layers={BLOOM_LAYER} visible={false}>
        <ringGeometry args={[0.32, 0.48, 32]} />
        <meshStandardMaterial
          color={meta.color}
          emissive={meta.color}
          emissiveIntensity={0}
          transparent
          opacity={0.85}
          side={DoubleSide}
          roughness={0.2}
          metalness={0.3}
        />
      </mesh>
    </group>
  );
}

