    antialias: false,
    shadows: true,
    shadowMapSize: 512,
    exposure: 1.12,
    postfx: 'off',
    n8ao: false,
    selectiveBloom: false,
    bloomIntensity: 0,
    physicalMaterials: false,
    innerPlatformRing: false,
    envPreset: 'apartment',
    envIntensity: 0.42,
    fog: true,
  },
  low: {
