*, *::before, *::after { box-sizing: border-box; }
html, body { height: 100%; margin: 0; }
body {
  font-family: system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
  background: var(--ui-bg);
  color: var(--ui-text);
  transition: background 0.35s var(--theme-ease), color 0.35s var(--theme-ease);
  overflow: hidden;
}

.hidden { display: none !important; }
.mobile-only { display: none; }
.desktop-only { display: flex; }

.app {
  display: flex;
  flex-direction: column;
  height: 100vh;
  height: 100dvh;
}

/* Topbar */
.topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 10px 16px;
  border-bottom: 1px solid var(--ui-border);
  background: rgba(255, 255, 255, 0.92);
  flex-shrink: 0;
  z-index: 50;
}
.topbar-brand h1 { margin: 0; font-size: 1.05rem; font-weight: 600; }
.badge-3d { color: var(--ui-accent-badge); font-weight: 400; font-size: 0.8rem; }
.subtitle { margin: 2px 0 0; font-size: 0.7rem; color: var(--ui-text-muted); }
.topbar-actions { display: flex; align-items: center; gap: 6px; flex-wrap: wrap; justify-content: flex-end; }
.render-mode {
  font-size: 0.68rem;
  color: var(--ui-brand-text);
  background: var(--ui-brand-soft);
  border: 1px solid var(--ui-brand-border);
  padding: 3px 8px;
  border-radius: 999px;
  white-space: nowrap;
}
.conn { display: flex; align-items: center; gap: 6px; font-size: 0.7rem; color: var(--ui-text-subtle); }
.conn-dot { width: 8px; height: 8px; border-radius: 50%; background: var(--ui-warning); animation: pulse 1.5s infinite; }
.conn-dot.live { background: var(--ui-live); animation: none; }
@keyframes pulse { 50% { opacity: 0.4; } }

.cloud-banner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  padding: 8px 16px;
  background: rgba(14, 116, 144, 0.12);
  border-bottom: 1px solid rgba(14, 116, 144, 0.25);
  font-size: 0.72rem;
  color: var(--ui-text);
}
.cloud-banner.hidden { display: none; }
.cloud-banner #btn-cloud-banner-close {
  flex-shrink: 0;
  min-width: 28px;
  padding: 2px 8px;
  font-size: 1rem;
  line-height: 1;
}

.active-task {
  padding: 8px 16px;
  background: var(--ui-brand-soft);
  border-bottom: 1px solid var(--ui-brand-border);
  font-size: 0.75rem;
  color: var(--ui-brand-text);
}
.active-task strong { color: var(--ui-brand-hover); }

/* Buttons */
.btn {
  border: none;
  border-radius: 8px;
  padding: 8px 14px;
  font-size: 0.8rem;
  font-weight: 500;
  cursor: pointer;
  transition: background 0.15s;
}
.btn-sm { padding: 5px 10px; font-size: 0.72rem; }
.btn-primary { background: var(--ui-brand); color: #fff; }
.btn-primary:hover { background: var(--ui-brand-hover); }
.btn-accent { background: #047857; color: #fff; }
.btn-accent:hover { background: var(--ui-success); }
.btn-ghost { background: var(--ui-surface-muted); color: var(--ui-text); }
.btn-ghost:hover { background: var(--ui-border); }

/* Main layout — desktop: office | chat+team */
.main-layout {
  flex: 1;
  display: grid;
  grid-template-columns: 1fr 420px;
  grid-template-rows: 1fr auto;
  min-height: 0;
  overflow: hidden;
}
.panel-office {
  grid-column: 1;
  grid-row: 1 / -1;
  display: flex;
  flex-direction: column;
  min-height: 0;
  border-right: 1px solid var(--ui-border);
}
.panel-chat {
  grid-column: 2;
  grid-row: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
  border-bottom: 1px solid var(--ui-border);
  background: var(--ui-surface);
}
.chat-layout {
  display: flex;
  flex: 1;
  min-height: 0;
}
.chat-sidebar {
  width: 132px;
  flex-shrink: 0;
  border-right: 1px solid var(--ui-border);
  display: flex;
  flex-direction: column;
  min-height: 0;
  background: var(--ui-surface-muted);
}
.chat-sidebar-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 8px 6px;
  font-size: 0.72rem;
  font-weight: 600;
  color: var(--ui-text-muted);
  border-bottom: 1px solid var(--ui-border);
}
.chat-list {
  list-style: none;
  margin: 0;
  padding: 6px;
  overflow-y: auto;
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.chat-list-item {
  width: 100%;
  text-align: left;
  border: 1px solid transparent;
  border-radius: var(--ui-radius-sm);
  background: transparent;
  padding: 7px 8px;
  cursor: pointer;
  font-size: 0.72rem;
  color: var(--ui-text);
}
.chat-list-item:hover {
  background: var(--ui-surface);
  border-color: var(--ui-border);
}
.chat-list-item.active {
  background: var(--ui-brand-soft);
  border-color: var(--ui-brand-border);
  color: var(--ui-brand-text);
  font-weight: 600;
}
.chat-list-row {
  display: flex;
  align-items: stretch;
  gap: 2px;
}
.chat-list-row .chat-list-item { flex: 1; min-width: 0; }
.chat-list-item .chat-item-path {
  display: block;
  margin-top: 2px;
  font-size: 0.62rem;
  color: var(--ui-text-muted);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.chat-delete-btn {
  flex-shrink: 0;
  width: 26px;
  border: 1px solid transparent;
  border-radius: var(--ui-radius-sm);
  background: transparent;
  color: var(--ui-text-muted);
  font-size: 0.85rem;
  cursor: pointer;
  opacity: 0;
  transition: opacity 0.15s, background 0.15s, color 0.15s;
}
.chat-list-row:hover .chat-delete-btn,
.chat-list-row:focus-within .chat-delete-btn {
  opacity: 1;
}
.chat-delete-btn:hover {
  background: rgba(220, 38, 38, 0.1);
  border-color: rgba(220, 38, 38, 0.25);
  color: #dc2626;
}
.chat-delete-btn:disabled {
  opacity: 0.25;
  cursor: not-allowed;
}
.chat-head-actions {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
}
.btn-delete-chat { color: #dc2626; }
.btn-delete-chat:disabled { opacity: 0.4; cursor: not-allowed; }
.browse-status {
  margin: 6px 0 0;
  font-size: 0.72rem;
  color: var(--ui-brand-text);
}
.browse-status.error { color: #dc2626; }
.browse-status.hidden { display: none; }
.chat-main {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
  min-width: 0;
}
.chat-panel-head .chat-head-top {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
}
.chat-panel-head h2 { margin: 0; flex: 1; min-width: 0; }
.chat-folder-path {
  margin: 4px 0 8px;
  font-size: 0.65rem;
  color: var(--ui-text-muted);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.chat-select-mobile {
  flex: 1;
  min-width: 0;
  border-radius: var(--ui-radius-sm);
  border: 1px solid var(--ui-border);
  background: var(--ui-surface-muted);
  color: var(--ui-text);
  font-size: 0.78rem;
  padding: 6px 8px;
}
.field-label {
  display: block;
  margin: 10px 0 4px;
  font-size: 0.75rem;
  color: var(--ui-text-muted);
}
.field-input {
  width: 100%;
  border-radius: var(--ui-radius-sm);
  border: 1px solid var(--ui-border);
  background: var(--ui-surface-muted);
  color: var(--ui-text);
  padding: 9px 10px;
  font-size: 0.85rem;
  font-family: inherit;
}
.field-input:focus { outline: 2px solid rgba(124, 58, 237, 0.4); }
.folder-row {
  display: flex;
  gap: 8px;
  align-items: center;
}
.folder-row .field-input { flex: 1; min-width: 0; }
.panel-team {
  grid-column: 2;
  grid-row: 2;
  max-height: 220px;
  overflow-y: auto;
  background: var(--ui-surface);
}
.panel-head { padding: 10px 14px; border-bottom: 1px solid var(--ui-border); }
.panel-head h2 { margin: 0; font-size: 0.85rem; }
.panel-head p { margin: 2px 0 0; font-size: 0.68rem; color: var(--ui-text-muted); }
.panel-toolbar { gap: 8px; padding: 8px 12px; border-bottom: 1px solid var(--ui-border); }

/* Office viewport */
.office-viewport {
  flex: 1;
  position: relative;
  min-height: 200px;
  background: radial-gradient(ellipse 90% 70% at 50% 40%, #d0dae6, #c2cad8);
}
.office-canvas-host-inner {
  width: 100%;
  height: 100%;
  min-height: 280px;
}
.office-canvas-host, .office-2d-host {
  position: absolute;
  inset: 0;
}
.office-canvas { display: block; width: 100%; height: 100%; }

.office-loader {
  position: absolute;
  inset: 0;
  z-index: 30;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  background: rgba(244, 246, 250, 0.9);
  gap: 12px;
  font-size: 0.85rem;
  color: var(--ui-text-muted);
}
.office-loader.done { opacity: 0; pointer-events: none; transition: opacity 0.4s; }
.loader-spin {
  width: 36px; height: 36px;
  border: 3px solid var(--ui-border);
  border-top-color: var(--ui-accent-badge);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

.head-labels-layer {
  position: absolute; inset: 0;
  pointer-events: none; overflow: hidden; z-index: 5;
}
.head-bubble {
  position: absolute; left: 0; top: 0;
  max-width: 220px; padding: 9px 12px;
  border-radius: var(--ui-radius-md);
  background: rgba(255, 255, 255, 0.92);
  backdrop-filter: blur(6px);
  -webkit-backdrop-filter: blur(6px);
  border: 1px solid var(--ui-brand-border);
  box-shadow: var(--ui-shadow-md);
  font-size: 10px; line-height: 1.4; color: var(--ui-text);
  transition: opacity 0.2s, transform 0.2s;
}
.head-bubble.hidden { opacity: 0 !important; visibility: hidden; }
.head-bubble-name {
  display: block; font-weight: 600; font-size: 9px;
  text-transform: uppercase; letter-spacing: 0.06em;
  color: var(--ui-brand-text); margin-bottom: 4px;
}
.name-tag {
  position: absolute; left: 0; top: 0;
  padding: 4px 10px; border-radius: var(--ui-radius-sm);
  font-size: 9px; font-weight: 500; letter-spacing: 0.02em;
  background: rgba(255, 255, 255, 0.9);
  backdrop-filter: blur(5px);
  -webkit-backdrop-filter: blur(5px);
  border: 1px solid var(--ui-border);
  color: var(--ui-text); white-space: nowrap;
  box-shadow: var(--ui-shadow-sm);
  transition: box-shadow 0.25s, border-color 0.25s, transform 0.2s;
}
.name-tag.talking {
  border-color: var(--accent, #8b5cf6);
  box-shadow:
    0 0 16px color-mix(in srgb, var(--accent, #8b5cf6) 45%, transparent),
    0 2px 12px rgba(0, 0, 0, 0.4);
}

.office-legend {
  position: absolute; top: 8px; right: 10px;
  display: flex; flex-direction: column; gap: 4px;
  font-size: 9px; color: var(--ui-text-muted); z-index: 6; pointer-events: none;
}
.office-3d-error {
  position: absolute; inset: 0; z-index: 25;
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  padding: 20px; text-align: center; background: rgba(244, 246, 250, 0.95);
  font-size: 13px;
}
.office-3d-error strong { color: #f87171; margin-bottom: 8px; }

/* Theme picker */
.theme-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
  gap: 10px;
}
.theme-card {
  cursor: pointer;
  border: 2px solid var(--ui-border);
  border-radius: var(--ui-radius-md);
  padding: 14px;
  transition: transform 0.2s var(--theme-ease), border-color 0.2s;
}
.theme-card:hover { transform: translateY(-2px); }
.theme-card.active { border-color: var(--ui-brand); }
.theme-card-dots { display: flex; gap: 6px; margin-bottom: 10px; }
.theme-card-dot { width: 18px; height: 18px; border-radius: 50%; }
.theme-card-name { font-weight: 700; font-size: 0.9rem; }
.theme-card-desc { font-size: 0.75rem; color: var(--ui-text-muted); margin-top: 3px; }

/* 2D fallback */
.iso-floor {
  position: relative; width: 100%; height: 100%; min-height: 280px;
  background: linear-gradient(165deg, var(--iso-bg-start) 0%, var(--iso-bg-end) 100%);
  transition: background 0.35s var(--theme-ease);
}
.iso-table {
  position: absolute; left: 42%; top: 42%; width: 16%; height: 10%;
  background: var(--iso-table); border-radius: 50%;
  box-shadow: 0 4px 16px rgba(100, 116, 139, 0.25);
  border: 2px solid var(--iso-table-border);
  transition: background 0.35s var(--theme-ease), border-color 0.35s var(--theme-ease);
}
.iso-room {
  position: absolute; transform: translate(-50%, -50%);
  width: 22%; min-width: 90px;
}
.iso-user-room .iso-desk { background: var(--iso-desk); }
.iso-user-room .iso-label { color: var(--iso-label); font-weight: 600; }
.iso-room.active .iso-monitor { box-shadow: 0 0 12px var(--accent); }
.iso-room.focused { outline: 2px solid #8b5cf6; outline-offset: 4px; border-radius: 8px; }
.iso-desk { height: 28px; background: var(--iso-desk); border-radius: 4px; margin-bottom: 4px; transition: background 0.35s var(--theme-ease); }
.iso-monitor {
  height: 20px; background: #2a3344; border: 2px solid var(--accent, #64748b);
  border-radius: 3px; margin-bottom: 6px;
  transition: box-shadow 0.3s;
}
.iso-agent {
  width: 44px; height: 44px; margin: 0 auto;
  border-radius: 12px; border: 2px solid var(--accent);
  background: rgba(240, 244, 250, 0.95);
  display: flex; align-items: center; justify-content: center;
  font-size: 1.4rem;
  transition: transform 0.4s ease, left 0.5s ease, top 0.5s ease;
  position: relative;
}
.iso-agent.typing { animation: bob 0.8s ease-in-out infinite; }
.iso-agent { position: absolute; transform: translate(-50%, -50%); }
@keyframes bob { 50% { transform: translate(-50%, calc(-50% - 4px)); } }
.iso-label { display: block; text-align: center; font-size: 9px; color: var(--iso-label); margin-top: 4px; }

/* Notifications */
.notify-stack {
  position: fixed; top: 10px; left: 50%; transform: translateX(-50%);
  z-index: 200; display: flex; flex-direction: column; gap: 6px;
  width: min(480px, calc(100vw - 20px));
  pointer-events: none; max-height: 35vh; overflow: hidden;
}
.notify-toast {
  display: flex; gap: 8px; padding: 8px 12px;
  border-radius: 10px;
  background: rgba(255, 255, 255, 0.96);
  border: 1px solid var(--ui-border); border-left-width: 3px;
  box-shadow: var(--ui-shadow-md);
  opacity: 0; transform: translateY(-12px);
  transition: opacity 0.3s, transform 0.3s;
  pointer-events: auto;
  max-height: 72px; overflow: hidden;
}
.notify-toast.show { opacity: 1; transform: translateY(0); }
.notify-emoji { font-size: 1.2rem; flex-shrink: 0; }
.notify-body { font-size: 10px; color: var(--ui-text-muted); min-width: 0; }
.notify-body strong { font-size: 11px; display: block; }
.notify-body p { margin: 2px 0 0; color: var(--ui-text); font-size: 11px; line-height: 1.3;
  overflow: hidden; text-overflow: ellipsis; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; }

/* Chat */
.chat-feed {
  flex: 1; overflow-y: auto; padding: 10px;
  display: flex; flex-direction: column; gap: 8px;
}
.chat-form {
  padding: 10px; border-top: 1px solid var(--ui-border);
  display: flex; flex-direction: column; gap: 8px; flex-shrink: 0;
}
.chat-form textarea {
  width: 100%; resize: none; border-radius: var(--ui-radius-sm);
  background: var(--ui-surface-muted); border: 1px solid var(--ui-border);
  color: var(--ui-text); padding: 10px; font-size: 0.85rem;
  font-family: inherit;
}
.chat-form textarea:focus { outline: 2px solid rgba(124, 58, 237, 0.4); }
.chat-actions { display: flex; gap: 8px; }
.chat-actions .btn { flex: 1; }

.msg {
  border-radius: var(--ui-radius-sm); background: var(--ui-surface-muted);
  padding: 8px 10px; font-size: 0.82rem;
  animation: msg-in 0.3s ease-out;
}
@keyframes msg-in { from { opacity: 0; transform: translateY(4px); } }
.msg-head { display: flex; align-items: center; gap: 6px; margin-bottom: 4px; }
.msg-head .name { font-size: 0.72rem; font-weight: 600; }
.msg-head .time { margin-left: auto; font-size: 0.65rem; color: var(--ui-text-muted); }
.msg-text { margin: 0; line-height: 1.4; white-space: pre-wrap; word-break: break-word; }
.msg-user { border-left: 3px solid #94a3b8; }
.msg-orchestrator { border-left: 3px solid #8b5cf6; }
.msg-designer { border-left: 3px solid #ec4899; }
.msg-frontend { border-left: 3px solid #06b6d4; }
.msg-backend { border-left: 3px solid #22c55e; }
.msg-owencloud { border-left: 3px solid #f59e0b; }
.msg-system { border-left: 3px solid #64748b; }

/* Team cards */
.team-cards { padding: 8px; display: flex; flex-direction: column; gap: 6px; }
.team-card {
  display: flex; align-items: center; gap: 10px;
  padding: 8px 10px; border-radius: var(--ui-radius-sm);
  background: var(--ui-surface); border: 1px solid var(--ui-border);
  cursor: pointer; transition: border-color 0.15s;
}
.team-card:hover { border-color: var(--accent, #64748b); }
.team-card .emoji { font-size: 1.3rem; }
.team-card .info { flex: 1; min-width: 0; }
.team-card .info strong { font-size: 0.78rem; display: block; }
.team-card .status-pill {
  display: inline-block; margin-top: 2px;
  padding: 1px 6px; border-radius: 999px;
  font-size: 0.62rem; text-transform: uppercase;
  background: var(--ui-surface-muted); color: var(--ui-text-muted);
}
.team-card .status-pill.working, .team-card .status-pill.thinking, .team-card .status-pill.talking {
  background: color-mix(in srgb, var(--accent) 30%, transparent);
  color: var(--ui-text);
}
.team-actions { display: flex; flex-wrap: wrap; gap: 6px; padding: 8px; }
.bridge-hint { padding: 8px 12px; font-size: 0.65rem; color: var(--ui-text-muted); }
.bridge-hint code { background: var(--ui-surface-muted); padding: 2px 5px; border-radius: 3px; color: var(--ui-text-subtle); }
.hint-cursor { margin-top: 4px; color: var(--ui-accent-badge); }

/* Modal */
.modal {
  position: fixed; inset: 0; z-index: 300;
  background: rgba(0,0,0,0.6);
  display: flex; align-items: center; justify-content: center;
  padding: 16px;
}
.modal-box {
  background: var(--ui-surface); border-radius: var(--ui-radius-md); padding: 20px;
  max-width: 400px; width: 100%;
  border: 1px solid var(--ui-border);
}
.modal-box h3 { margin: 0 0 8px; font-size: 1rem; }
.modal-box p { margin: 0 0 12px; font-size: 0.8rem; color: var(--ui-text-muted); }
.lan-urls { display: flex; flex-direction: column; gap: 8px; margin-bottom: 14px; }
.lan-url {
  display: flex; align-items: center; gap: 8px;
  background: var(--ui-surface-muted); padding: 8px 10px; border-radius: var(--ui-radius-sm);
  font-size: 0.75rem; word-break: break-all;
}
.lan-url button { flex-shrink: 0; }

/* Question modal */
.question-box { max-width: 440px; }
.question-head {
  display: flex; align-items: center; gap: 10px;
  margin-bottom: 10px;
}
.q-emoji { font-size: 1.5rem; line-height: 1; }
.q-text {
  margin: 0 0 12px; font-size: 0.9rem; line-height: 1.45;
  color: var(--ui-text);
}
.q-image {
  display: block; width: 100%; max-height: 200px;
  object-fit: contain; border-radius: var(--ui-radius-sm);
  margin-bottom: 12px; border: 1px solid var(--ui-border);
  background: var(--ui-surface-muted);
}
.q-options {
  display: flex; flex-direction: column; gap: 6px;
  margin-bottom: 10px;
}
.q-option-btn {
  width: 100%; text-align: left;
  border: 1px solid var(--ui-border);
  background: var(--ui-surface-muted);
}
.q-option-btn:hover {
  border-color: var(--ui-brand-border);
  background: var(--ui-brand-soft);
}
.question-box textarea {
  width: 100%; resize: none; border-radius: var(--ui-radius-sm);
  background: var(--ui-surface-muted); border: 1px solid var(--ui-border);
  color: var(--ui-text); padding: 10px; font-size: 0.85rem;
  font-family: inherit; margin-bottom: 10px;
}
.question-box textarea:focus { outline: 2px solid rgba(124, 58, 237, 0.4); }
.question-actions { display: flex; gap: 8px; }
.question-actions .btn { flex: 1; }

/* Action modal */
.action-box { max-width: 480px; }
.a-reason {
  margin: 0 0 10px; font-size: 0.85rem; line-height: 1.4;
  color: var(--ui-text-muted);
}
.a-command {
  margin: 0 0 10px; padding: 10px 12px;
  background: var(--ui-surface-muted); border: 1px solid var(--ui-border);
  border-radius: var(--ui-radius-sm);
  font-family: ui-monospace, 'Cascadia Code', Consolas, monospace;
  font-size: 0.78rem; line-height: 1.45;
  white-space: pre-wrap; word-break: break-all;
  color: var(--ui-text); max-height: 160px; overflow: auto;
}
.a-hint {
  margin: 0 0 12px; font-size: 0.72rem;
  color: var(--ui-text-muted); line-height: 1.35;
}

/* Session banner */
.session-banner {
  display: flex; align-items: center; justify-content: space-between; gap: 8px;
  margin: 6px 0 4px; padding: 6px 10px;
  border-radius: var(--ui-radius-sm);
  background: rgba(34, 197, 94, 0.12);
  border: 1px solid rgba(34, 197, 94, 0.35);
  font-size: 0.75rem; color: var(--ui-text);
}
.session-banner.flash {
  background: rgba(124, 58, 237, 0.12);
  border-color: rgba(124, 58, 237, 0.35);
}
.session-box { max-width: 440px; }
.btn-session-kill { flex-shrink: 0; color: #ef4444; }

/* Photo attachments */
.photo-preview {
  display: flex; flex-direction: column; gap: 8px;
  padding: 8px; border-radius: var(--ui-radius-sm);
  background: var(--ui-surface-muted); border: 1px solid var(--ui-border);
}
.photo-preview-grid {
  display: flex; flex-wrap: wrap; gap: 6px;
}
.photo-preview-item {
  position: relative; flex-shrink: 0;
}
.photo-preview-item img {
  display: block; width: 64px; height: 64px;
  object-fit: cover; border-radius: 6px;
  border: 1px solid var(--ui-border);
}
.photo-preview-remove {
  position: absolute; top: -6px; right: -6px;
  width: 20px; height: 20px; padding: 0;
  border-radius: 50%; border: 1px solid var(--ui-border);
  background: var(--ui-surface); color: var(--ui-text-muted);
  font-size: 0.65rem; cursor: pointer; line-height: 1;
}
.photo-preview-remove:hover { color: #dc2626; border-color: rgba(220, 38, 38, 0.4); }
.photo-preview-actions {
  display: flex; align-items: center; justify-content: space-between; gap: 8px;
}
.photo-upload-status {
  font-size: 0.72rem; color: var(--ui-brand-text);
}
.msg-photos-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
  gap: 6px; margin-top: 8px;
}
.msg-photos-grid .msg-photo-link { margin-top: 0; }
.msg-photos-grid .msg-photo {
  width: 100%; max-height: 120px; object-fit: cover;
}
.msg-photo-link { display: block; margin-top: 8px; }
.msg-photo {
  display: block; max-width: 100%; max-height: 220px;
  border-radius: var(--ui-radius-sm); border: 1px solid var(--ui-border);
  object-fit: contain; background: var(--ui-surface-muted);
}
.msg-photo-link:hover .msg-photo { border-color: var(--ui-brand-border); }

/* Launcher app mode */
.app-mode-badge {
  color: var(--ui-success); font-weight: 500;
  font-size: 0.68rem;
}
.user-desk-tag {
  border-color: #94a3b8 !important;
  font-weight: 600;
}

/* Mobile */
@media (max-width: 1023px) {
  .mobile-only { display: flex; }
  .desktop-only { display: none !important; }

  .main-layout {
    grid-template-columns: 1fr;
    grid-template-rows: 1fr;
  }
  .panel-office, .panel-chat, .panel-team {
    grid-column: 1; grid-row: 1;
    display: none;
