      updateGfxButtons();
      setTimeout(() => window.dispatchEvent(new Event('resize')), 100);
      return;
    }
  }
  hideLoader();
  alert('3D не загрузился. Обновите страницу (Ctrl+F5) или проверьте WebGL в браузере.');
